if (! function_exists('pattern_mixer')) {
    function pattern_mixer($canvas_a, $canvas_b, $method, $fill_char = null)
    {
        $linesA = explode("\n", $canvas_a);
        $linesB = explode("\n", $canvas_b);

        $h = max(count($linesA), count($linesB));
        $w = 0;
        foreach (array_merge($linesA, $linesB) as $line) {
            $w = max($w, strlen(rtrim($line, "\r")));
        }

        // Pad all rows to same width
        function padRows(&$rows, $w, $h) {
            $result = [];
            for ($y = 0; $y < $h; $y++) {
                $line = isset($rows[$y]) ? rtrim($rows[$y], "\r") : '';
                if (strlen($line) < $w) {
                    $line .= str_repeat(' ', $w - strlen($line));
                }
                $result[] = $line;
            }
            return $result;
        }

        $gridA = padRows($linesA, $w, $h);
        $gridB = padRows($linesB, $w, $h);
        $fill = isset($fill_char) && $fill_char !== '' ? $fill_char[0] : '#';
        $bg = ' ';

        $output = [];

        for ($y = 0; $y < $h; $y++) {
            $row = '';
            for ($x = 0; $x < $w; $x++) {
                $cA = $gridA[$y][$x] ?? ' ';
                $cB = $gridB[$y][$x] ?? ' ';
                $isFilledA = ($cA !== ' ' && $cA !== "\0");
                $isFilledB = ($cB !== ' ' && $cB !== "\0");

                switch ($method) {
                    case 'overlay':
                        // B overwrites A
                        $row .= $isFilledB ? $cB : $cA;
                        break;
                    case 'alternate':
                        $row .= (($x + $y) % 2 === 0) ? $cA : $cB;
                        break;
                    case 'xor':
                        $row .= ($isFilledA xor $isFilledB) ? $fill : $bg;
                        break;
                    case 'union':
                        $row .= ($isFilledA || $isFilledB) ? $fill : $bg;
                        break;
                    case 'intersection':
                        $row .= ($isFilledA && $isFilledB) ? $fill : $bg;
                        break;
                    default:
                        $row .= $cA;
                }
            }
            $output[] = $row;
        }

        return json_encode([
            'canvas' => implode("\n", $output),
            'width' => $w,
            'height' => $h,
            'method' => $method,
            'characters' => $w * $h
        ]);
    }
